/* ---------- model lab (shadow scoreboard) ---------- */
if (WC26.shadow_scores && $("lab-board")) {
  // pin the PRODUCTION model first (it's what's actually deployed); the rest are
  // what-ifs, sorted. Over so few matches the order is noise, so don't let the
  // deployed model look "mid-table" just because of a thousandth of log-loss.
  const all = [...WC26.shadow_scores];
  const deployed = all.find((r) => r.variant === "Full model");
  const rest = all.filter((r) => r !== deployed).sort((x, y) => x.log_loss - y.log_loss);
  const rows = deployed ? [deployed, ...rest] : rest;
  const n = rows[0]?.n || 0;
  const spread = Math.max(...all.map((r) => r.log_loss)) - Math.min(...all.map((r) => r.log_loss));
  const uni = WC26.uniform_logloss;
  const lo = Math.min(...rows.map((r) => r.log_loss), uni) - 0.01;
  const hi = Math.max(...rows.map((r) => r.log_loss), uni) + 0.01;
  const w = (v) => (100 * (hi - v)) / (hi - lo);
  $("lab-board").innerHTML = rows.map((r) => {
    const main = r.variant === "Full model";
    const shadow = r.variant.includes("shadow");
    const col = main ? "linear-gradient(90deg, var(--accent2), var(--accent))" : shadow ? "var(--gold)" : "#51618f";
    return `<div class="bar-row">
      <div class="who">${main ? `<b>${r.variant}</b> <span class="prod-badge">▶ in production</span>` : r.variant}</div>
      <div class="bar-track"><div class="bar-fill" style="width:${w(r.log_loss)}%;background:${col}"></div></div>
      <div class="val">${r.log_loss.toFixed(3)}</div>
    </div>`;
  }).join("");
  $("lab-note").innerHTML =
    `The <strong>top row is the model actually in production</strong>; every other line is the same model
     with one ingredient added or removed — a what-if. Shorter bar = better (lower log-loss; know-nothing
     baseline ${uni.toFixed(3)}). Crucially, over the ${n} matches played so far the whole field is spread
     by just <strong>${spread.toFixed(3)}</strong> log-loss — <strong>statistically tied</strong>, far too
     few games to separate them, so the ordering here is noise (the deployed model beating "Elo only" and
     "no altitude" is the only real signal: the tilts help). The two gold bars are shadow bets that live
     here and <strong>only</strong> here. <strong>This live board never decides what goes in the model —
     the 345-match backtest does.</strong>`;
}

/* ---------- footer ---------- */
if ($("footer-meta")) {
  $("footer-meta").textContent =
    `Generated ${WC26.generated} · ${WC26.model_version} · ${WC26.n_sims.toLocaleString("en-US")} simulations, seed ${WC26.seed} · ` +
    `WC2022 backtest log-loss ${WC26.backtest.log_loss_model} (uniform ${WC26.backtest.log_loss_uniform}).`;
}

/* ---------- how it's doing: live track record + real standings ---------- */
if (WC26.scoring && WC26.scoring.n && $("track-head")) {
  const s = WC26.scoring;
  $("track-head").innerHTML = `
    <div class="stat"><div class="v">${s.log_loss}</div><div class="k">live log-loss (uniform ${s.uniform})</div></div>
    <div class="stat"><div class="v">${s.n}</div><div class="k">real matches scored</div></div>
    <div class="stat"><div class="v">${pct(s.fav_predicted,0)} → ${pct(s.fav_observed,0)}</div><div class="k">favourites: predicted vs won</div></div>`;
  const M = { H: "home win", D: "draw", A: "away win" };
  $("track-matches").innerHTML = [...s.matches].reverse().map((m) => {
    const good = m.p_realised >= 0.45;
    const has = MD[m.home + "|" + m.away] ? "clickable" : "";
    const hint = has ? `<span class="mh-hint">distribution ▸</span>` : "";
    const [hg, ag] = (m.score || "–").split(/[–-]/);
    return `<div class="sb-row ${has}" data-home="${m.home}" data-away="${m.away}">
      <div class="sb-match">
        <span class="sb-team">${flag(m.home)}${m.home}</span>
        <span class="sb-score">${hg ?? ""}<i>–</i>${ag ?? ""}</span>
        <span class="sb-team away">${m.away}${flag(m.away)}</span>
        ${coinFlipBadge(m.home, m.away)}${hint}
      </div>
      <div class="sb-p ${good ? "win" : "miss"} tnum" title="probability the model gave to what actually happened">${pct(m.p_realised, 0)}</div>
    </div>`;
  }).join("");
  $("track-matches").querySelectorAll(".sb-row.clickable").forEach((row) =>
    row.addEventListener("click", () => showHeat(row.dataset.home, row.dataset.away)));
  if (WC26.standings && $("track-standings")) {
    $("track-standings").innerHTML = Object.keys(WC26.standings).sort().map((g) => {
      const rows = WC26.standings[g].map((r, i) => `
        <div class="row"><span>${i < 2 ? "<b>" : ""}${flag(r.team)}${r.team}${i < 2 ? "</b>" : ""}</span>
          <span>${r.Pts}p · ${r.GD > 0 ? "+" : ""}${r.GD}</span></div>`).join("");
      return `<div class="tlg"><b>GROUP ${g}</b>${rows}</div>`;
    }).join("");
  }
}
